import { Component, OnInit, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ActivatedRoute, RouterLink } from '@angular/router';
import { AuthService } from '../../core/services/auth.service';
import { Product, PurchaseOrder, PurchaseOrderLine } from '../../core/models';

/**
 * Purchase order detail: line-item editor (draft only) + status-transition
 * buttons (Place order → ordered, Receive → received, incrementing stock).
 * Buttons are disabled by role and status. service_agent wires
 * getPurchaseOrder / update / orderPO / receivePO.
 */
@Component({
  selector: 'app-purchase-order-detail',
  standalone: true,
  imports: [CommonModule, FormsModule, RouterLink],
  templateUrl: './purchase-order-detail.component.html',
  styleUrl: './purchase-order-detail.component.css',
})
export class PurchaseOrderDetailComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);
  readonly working = signal(false);
  id = '';

  readonly products = signal<Product[]>([
    { id: 'p1', sku: 'WID-001', name: 'Widget', costCents: 450, priceCents: 999, onHand: 120 },
    { id: 'p2', sku: 'GAD-002', name: 'Gadget', costCents: 1200, priceCents: 2499, onHand: 64 },
    { id: 'p3', sku: 'SPR-003', name: 'Sprocket', costCents: 80, priceCents: 249, onHand: 340 },
  ]);

  readonly order = signal<PurchaseOrder>({
    id: 'po1',
    supplierId: 's1',
    status: 'draft',
    createdAt: '2026-07-08T10:00:00Z',
    supplier: { id: 's1', name: 'Globex Supply Co', email: 'sales@globex.example' },
    lines: [
      { id: 'l1', poId: 'po1', productId: 'p1', qty: 100, unitCostCents: 450,
        product: { id: 'p1', sku: 'WID-001', name: 'Widget', costCents: 450, priceCents: 999, onHand: 120 } },
      { id: 'l2', poId: 'po1', productId: 'p3', qty: 500, unitCostCents: 80,
        product: { id: 'p3', sku: 'SPR-003', name: 'Sprocket', costCents: 80, priceCents: 249, onHand: 340 } },
    ],
  });

  readonly canEdit = computed(() => this.auth.isPurchasing());
  readonly isDraft = computed(() => this.order().status === 'draft');
  readonly totalCents = computed(() =>
    (this.order().lines ?? []).reduce((sum, l) => sum + l.qty * l.unitCostCents, 0),
  );

  // New-line form.
  newLine = { productId: '', qty: '1' };

  constructor(public auth: AuthService, private route: ActivatedRoute) {}

  ngOnInit(): void {
    this.id = this.route.snapshot.paramMap.get('id') ?? '';
    this.newLine.productId = this.products()[0]?.id ?? '';
    // service_agent: this.order.set(await ApiService.getPurchaseOrder(this.id)).
  }

  money(cents: number): string {
    return (cents / 100).toLocaleString(undefined, { style: 'currency', currency: 'USD' });
  }

  addLine(): void {
    const p = this.products().find((x) => x.id === this.newLine.productId);
    if (!p) return;
    const qty = Math.max(1, parseInt(this.newLine.qty || '1', 10));
    const line: PurchaseOrderLine = {
      id: 'l' + Date.now(),
      poId: this.order().id,
      productId: p.id,
      qty,
      unitCostCents: p.costCents,
      product: p,
    };
    this.order.update((o) => ({ ...o, lines: [...(o.lines ?? []), line] }));
    this.newLine.qty = '1';
  }

  removeLine(lineId: string): void {
    this.order.update((o) => ({ ...o, lines: (o.lines ?? []).filter((l) => l.id !== lineId) }));
  }

  placeOrder(): void {
    this.working.set(true);
    // service_agent: ApiService.orderPO(this.id).subscribe(...)
    this.order.update((o) => ({ ...o, status: 'ordered' }));
    this.working.set(false);
  }

  receive(): void {
    this.working.set(true);
    // service_agent: ApiService.receivePO(this.id) — backend increments onHand.
    this.order.update((o) => ({ ...o, status: 'received' }));
    this.working.set(false);
  }
}
